good-example.code-block:
public RoutedOrder route(ClientOrder order) {
    orderPolicy.requireTradable(order.instrumentId(), order.clientId());
    ClientInstruction instruction = instructionStore.currentInstruction(order.orderId());
    RoutingDecision decision = routingPolicy.selectVenue(
        order,
        instruction,
        executionPolicy.currentVersion(),
        marketData.snapshot(order.instrumentId())
    );

    RoutedOrder routed = gateway.submit(decision.venue(), order);

    orderAudit.record(new OrderRoutingAuditEvent(
        order.orderId(),
        order.clientId(),
        order.instrumentId(),
        instruction.id(),
        decision.policyVersion(),
        decision.venue(),
        routed.venueOrderId(),
        clock.instant()
    ));

    bestExecutionMetrics.recordDecision(order, decision);
    return routed;
}

